pub(crate) scheduled: Histogram,
pub(crate) async_commitment: Histogram,
pub(crate) async_settlement: Histogram,

pub(crate) scheduled: usize,
pub(crate) async_commitment: usize,
pub(crate) async_settlement: usize,
pub(crate) passkey: usize,

TxType::Scheduled => { self.scheduled += 1; }
TxType::AsyncCommitment => { self.async_commitment += 1; }
TxType::AsyncSettlement => { self.async_settlement += 1; }
TxType::Passkey => { self.passkey += 1; }

self.scheduled.record(tx_types_counter.scheduled as f64);
self.async_commitment.record(tx_types_counter.async_commitment as f64);
self.async_settlement.record(tx_types_counter.async_settlement as f64);
